def main():
    target_dir = os.path.join(os.path.dirname(__file__), "media", "oge15")
    os.makedirs(target_dir, exist_ok=True)
    ctx = ssl.create_default_context()
    ctx.check_hostname = False
    ctx.verify_mode = ssl.CERT_NONE
    for fname, url in IMAGES:
        path = os.path.join(target_dir, fname)
        if os.path.exists(path):
            print("  exists:", fname); continue
        try:
            req = urllib.request.Request(url, headers={
                "User-Agent": "Mozilla/5.0",
                "Referer": "https://oge.fipi.ru/bank/index.php?proj=DE0E276E497AB3784C3FC4CC20248DC0",
            })
            with urllib.request.urlopen(req, context=ctx, timeout=20) as r:
                data = r.read()
            with open(path, "wb") as f:
                f.write(data)
            print("  OK    ", fname, "(%d bytes)" % len(data))
        except Exception as e:
            print("  FAIL  ", fname, ":", e)
    print("\nDone:", target_dir)


if __name__ == "__main__":
    main()